css.codex:
/* 鹰羽信条 / codex / 原创致敬主题 */
html.codedrobe-host-codex {
  --tribute-bg: #171614;
  --tribute-surface: #25231F;
  --tribute-surface-alt: #EEE9DE;
  --tribute-text: #F5F0E6;
  --tribute-muted: #B5AA99;
  --tribute-accent: #A72F35;
  --tribute-accent-2: #B28B57;
  --tribute-border: #5D554A;
  color-scheme: dark;
}
html.codedrobe-host-codex body {
  color: var(--tribute-text);
  background:
    linear-gradient(rgba(0,0,0,.12), rgba(0,0,0,.22)),
    var(--codedrobe-image-hero) center / cover fixed,
    var(--tribute-bg);
}
html.codedrobe-host-codex body::before {
  content: "";
  position: fixed;
  inset: 0;
  z-index: -1;
  pointer-events: none;
  background: var(--codedrobe-image-ambient) center / cover no-repeat;
  opacity: .72;
}
html.codedrobe-host-codex main,
html.codedrobe-host-codex aside,
html.codedrobe-host-codex nav,
html.codedrobe-host-codex section,
html.codedrobe-host-codex [role="dialog"] {
  color: var(--tribute-text);
}
html.codedrobe-host-codex main,
html.codedrobe-host-codex [role="main"] {
  background: color-mix(in srgb, var(--tribute-bg) 78%, transparent);
  backdrop-filter: blur(14px) saturate(118%);
}
html.codedrobe-host-codex aside,
html.codedrobe-host-codex nav {
  background: color-mix(in srgb, var(--tribute-surface) 88%, transparent);
  backdrop-filter: blur(18px) saturate(120%);
}
html.codedrobe-host-codex button,
html.codedrobe-host-codex input,
html.codedrobe-host-codex textarea,
html.codedrobe-host-codex [contenteditable="true"],
html.codedrobe-host-codex [role="textbox"] {
  color: var(--tribute-text);
  border-color: var(--tribute-border);
  background: color-mix(in srgb, var(--tribute-surface) 91%, transparent);
}
html.codedrobe-host-codex button:hover,
html.codedrobe-host-codex [aria-selected="true"],
html.codedrobe-host-codex [data-state="active"] {
  border-color: var(--tribute-accent-2);
  background: color-mix(in srgb, var(--tribute-accent) 18%, var(--tribute-surface));
}
html.codedrobe-host-codex :focus-visible { outline: 2px solid var(--tribute-accent-2); outline-offset: 2px; }
html.codedrobe-host-codex a { color: var(--tribute-accent-2); }
html.codedrobe-host-codex pre,
html.codedrobe-host-codex code {
  background: #11100E;
  color: var(--tribute-text);
  border-color: var(--tribute-border);
}
html.codedrobe-host-codex blockquote { border-left-color: var(--tribute-accent); color: var(--tribute-muted); }
html.codedrobe-host-codex ::selection { background: color-mix(in srgb, var(--tribute-accent) 52%, transparent); color: var(--tribute-text); }
html.codedrobe-host-codex ::-webkit-scrollbar-thumb { background: color-mix(in srgb, var(--tribute-accent-2) 48%, var(--tribute-surface)); border-radius: 999px; }
html.codedrobe-host-codex .codedrobe-theme-emblem {
  pointer-events: none;
  background: var(--codedrobe-image-emblem) center / contain no-repeat;
}

html.codedrobe-host-codex [data-testid="composer"],
html.codedrobe-host-codex [contenteditable="true"],
html.codedrobe-host-codex textarea { box-shadow: 0 0 0 1px #5D554A, 0 18px 48px rgba(0,0,0,.28); }
html.codedrobe-host-codex pre { border-left: 3px solid #A72F35; }
@media (prefers-reduced-motion: reduce) {
  html.codedrobe-host-codex *, html.codedrobe-host-codex *::before, html.codedrobe-host-codex *::after { animation-duration: .01ms !important; transition-duration: .01ms !important; }
}

